// Javascript solution with 2 pointers
var patternMatcher = function(pattern, input) {
    const p_length = pattern.length;
    const i_length = input.length;
    let p_pointer = 0;
    let i_pointer = 0;
    while(i_pointer < i_length && p_pointer < p_length) {
        if(pattern[p_pointer] === '?') {
            p_pointer = p_pointer + 1;    
        }
        else if(pattern[p_pointer] !== input[i_pointer]) {
            if(pattern[p_pointer+1] === '?') {
                p_pointer = p_pointer + 2; 
            } else {
                return false;
            }
        } else {
            p_pointer++;
            i_pointer++;
        }
    }
    // if anything left in pattern or input
    if(p_pointer < p_length || i_pointer < i_length) {
        // special case - pattern has 2 characters and last one is ?
        // console.log("p_pointer: ", p_pointer);
        // console.log("p_length: ", p_length);
        if((p_length - p_pointer) <= 2 && pattern[p_length-1] === '?') {
            return true; // rule 1
        }
        return false;
    }

    // pattern matched
    return true;

}

